"use client";
import SectionBox from "./sectionBox";
import styles from "./headerHome.module.css"
import NavbarHome from "../_navbar/navbarHome";
import { useEffect, useRef } from "react";
import Matter from "matter-js";


export default function HeaderHome() {

  return (
    <SectionBox filter={false}>
      <PhysicsSection />
      <div className={styles["header-home-container"]}>
        <NavbarHome />
        <h1 className={styles["header-home-title"]}>{"Joshua\nDeveloper"}</h1>
      </div>
    </SectionBox>
  )
}



export function PhysicsSection() {
  const sceneRef = useRef(null);

  useEffect(() => {
    const {
      Engine,
      Render,
      Runner,
      Bodies,
      World,
    } = Matter;

    const section = sceneRef.current as HTMLElement | null;
    if (!section) return;

    // Engine
    const engine = Engine.create();
    const world = engine.world;

    // Render
    const render = Render.create({
      element: section,
      engine: engine,
      options: {
        width: section.clientWidth,
        height: section.clientHeight,
        wireframes: false,
        background: "transparent", // Cambiado a transparente
        pixelRatio: window.devicePixelRatio || 1
      }
    });

    Render.run(render);

    // Runner
    const runner = Runner.create();
    Runner.run(runner, engine);

    // Shapes
    const shapes = [
      Bodies.rectangle(200, 0, 80, 80, {
        restitution: 0.8,
        render: { fillStyle: "#ff6b6b" }
      }),

      Bodies.circle(400, 0, 40, {
        restitution: 0.9,
        render: { fillStyle: "#4ecdc4" }
      }),

      Bodies.polygon(600, 0, 3, 50, {
        restitution: 0.8,
        render: { fillStyle: "#ffe66d" }
      }),

      Bodies.polygon(300, 0, 5, 50, {
        restitution: 0.7,
        render: { fillStyle: "#c7f464" }
      }),

      Bodies.polygon(500, 0, 6, 50, {
        restitution: 0.7,
        render: { fillStyle: "#5f27cd" }
      })
    ];

    // Ground
    const ground = Bodies.rectangle(
      section.clientWidth / 2,
      section.clientHeight - 10,
      section.clientWidth,
      20,
      {
        isStatic: true,
        render: { fillStyle: "skyblue", visible: false } // mismo color que fondo, sin borde
      }
    );

    // Walls
    const leftWall = Bodies.rectangle(0, section.clientHeight / 2, 20, section.clientHeight, {
      isStatic: true,
      render: { fillStyle: "skyblue", visible: false } // mismo color que fondo, sin borde
    });

    const rightWall = Bodies.rectangle(
      section.clientWidth,
      section.clientHeight / 2,
      20,
      section.clientHeight,
      {
        isStatic: true,
        render: { fillStyle: "skyblue", visible: false } // mismo color que fondo, sin borde
      }
    );

    World.add(world, [...shapes, ground, leftWall, rightWall]);

    // Mouse interaction
   

    // Resize handler
    const handleResize = () => {
      render.canvas.width = section.clientWidth;
      render.canvas.height = section.clientHeight;
    };

    window.addEventListener("resize", handleResize);
//giiroscopio mobile

// 📱 --- GIROSCOPIO / DEVICE ORIENTATION ---


    // Cleanup (MUY importante en React)
    return () => {
      window.removeEventListener("resize", handleResize);
      Render.stop(render);
      Runner.stop(runner);
      World.clear(world);
      Engine.clear(engine);
      render.canvas.remove();
      render.textures = {};
    };
  }, []);

  return (
    <div
      style={{
        width: "100vw", // Responsive
        maxWidth: "100%",
        height: "60vh", // Responsive
        maxHeight: "80vh",
        backgroundColor: "skyblue",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <section
        ref={sceneRef}
        style={{
          width: "100%",
          height: "100%",
          overflow: "hidden",
          // border: "none", // Eliminado el borde
        }}
      />
    </div>
  );
}